generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Measures motor current \(I_M\) from the permanent magnet synchronous motor."
    DTDFVocab:producedData MotorCurrentDataMQTT
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Provides angular position and velocity from the motor encoder."
    DTDFVocab:producedData MotorEncoderDataMQTT
]

instance PostGearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Provides angular position and velocity from the post‑gearbox encoder."
    DTDFVocab:producedData PostGearboxEncoderDataMQTT
]

// C4: Physical‑to‑virtual interaction
instance MotorCurrentDataMQTT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderDataMQTT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance PostGearboxEncoderDataMQTT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom PostGearboxPositionEncoder
]

// C10: Models/Data (Sensor data)
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Cross‑validated motor current trace received via MQTT."
    DTDFVocab:fromData MotorCurrentDataMQTT
    DTDFVocab:inputTo MQTTBroker, SimulinkTool
]

instance MotorEncoderData : DTDFVocab:Data [
    base:desc "Cross‑validated motor encoder position and velocity trace via MQTT."
    DTDFVocab:fromData MotorEncoderDataMQTT
    DTDFVocab:inputTo MQTTBroker, SimulinkTool
]

instance PostGearboxEncoderData : DTDFVocab:Data [
    base:desc "Cross‑validated post‑gearbox encoder position and velocity trace via MQTT."
    DTDFVocab:fromData PostGearboxEncoderDataMQTT
    DTDFVocab:inputTo MQTTBroker, SimulinkTool
]

// C11: Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker for data streaming between physical sensors and virtual models."
    DTDFVocab:enables RealTimeFrictionModelIdentification, DataAggregation
]

instance SimulinkTool : DTDFVocab:Enabler [
    base:desc "Simulink environment for executing friction model simulations."
    DTDFVocab:enables RealTimeFrictionModelIdentification, DigitalTwinFoundation
]

instance SysMLTool : DTDFVocab:Enabler [
    base:desc "SysML tool for structural modelling of the motor‑gearbox system."
    DTDFVocab:enables DigitalTwinFoundation
]

instance DashboardUI : DTDFVocab:Enabler [
    base:desc "UI dashboard for visualizing real‑time data and friction parameters."
    DTDFVocab:enables DigitalShadowDashboard
]

instance CPlusPlusProcessor : DTDFVocab:Enabler [
    base:desc "C++ processing component for realtime data preprocessing."
    DTDFVocab:enables DataAggregation
]

// C10: Models
instance SysMLStructuralModel : DTDFVocab:Model [
    base:desc "SysML BDD/IBD structural model of the permanent magnet synchronous motor and gearboxes."
    DTDFVocab:inputTo SysMLTool
]

instance SimulinkCoulombViscousModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a Coulomb‑Viscous friction model for the motor‑gear system."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkStribeckModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a Stribeck friction model for the motor‑gear system."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkDahlModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a Dahl friction model for the motor‑gear system."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkLuGreModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a LuGre friction model for the motor‑gear system."
    DTDFVocab:inputTo SimulinkTool
]

// C6: Services
instance RealTimeFrictionModelIdentification : DTDFVocab:Service [
    base:desc "Real‑time friction model identification and visualization."
    DTDFVocab:provides FrictionLossTrendInsight, AutomaticFrictionModelParameterUpdate
]

instance DataAggregation : DTDFVocab:Service [
    base:desc "Aggregates data traces of measured and simulated torque and angular velocity."
    DTDFVocab:provides AggregateDataInsight
]

instance DigitalShadowDashboard : DTDFVocab:Service [
    base:desc "Visualizes real‑time data and friction model parameters in a digital shadow dashboard."
    DTDFVocab:provides DigitalShadowVisualizationInsight
]

instance DigitalTwinFoundation : DTDFVocab:Service [
    base:desc "Provides the foundation for comprehensive digital twin creation."
]

// C17: Insights and Actions
instance FrictionLossTrendInsight : DTDFVocab:Insight [
    base:desc "Insight into friction loss trends over time, informing maintenance planning."
]

instance AggregateDataInsight : DTDFVocab:Insight [
    base:desc "Insight into aggregated data, enabling consolidated analysis."
]

instance DigitalShadowVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight into real‑time visualization within the digital shadow dashboard."
]

instance AutomaticFrictionModelParameterUpdate : DTDFVocab:Action [
    base:desc "Automatic updating of friction model parameters enabling improved motion control accuracy."
    DTDFVocab:IsAutomatic true
]

instance MaintenancePlanningAction : DTDFVocab:Action [
    base:desc "Action to plan maintenance based on friction loss insights."
    DTDFVocab:IsAutomatic false
]

// C3: Physical components
instance MotorPsmsym : DTDFVocab:Component [
    base:desc "Permanent magnet synchronous motor of the first axis."
]

instance Gearwheel : DTDFVocab:Component [
    base:desc "Gearwheel in the first gearbox of the MABI MAX 100 axis."
]

instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox in the second stage of the MABI MAX 100 axis."
]

// C6: Environment
instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:contains MotorPsmsym, Gearwheel, CycloidalGearbox, MotorPositionEncoder, PostGearboxPositionEncoder
]

